1	// Recall.ai live Teams utterance worker.
2	//
3	// This processes finalized `transcript.data` events, not partial/provisional
4	// STT hypotheses. Each finalized utterance is persisted as a `messages` row for
5	// evidence/backfill, then a tightly gated Oracle pass decides whether a useful
6	// one-question interjection should be posted back to the Teams meeting chat.
7	
8	import { task } from '@trigger.dev/sdk/v3';
9	import { and, desc, eq, gte, isNull, sql } from 'drizzle-orm';
10	import { z } from 'zod';
11	import { createHash } from 'node:crypto';
12	import { getDirectDb } from '@oracle/db/client';
13	import {
14	  channelParticipants,
15	  channels,
16	  employees,
17	  jobRuns,
18	  messages,
19	  modelRuns,
20	  modelRunUsageDetails,
21	  oracleContextPacks,
22	  oracleInterventions,
23	  settings,
24	} from '@oracle/db/schema';
25	import {
26	  OracleAIClient,
27	  buildStandardAdapters,
28	  getOracleRoute,
29	  makeBlock,
30	  resolveRouteFromSettings,
31	  type OracleModelRoute,
32	} from '@oracle/ai';
33	import { sendRecallChatMessage } from '../lib/recall';
34	
35	const FALLBACK_INTERVIEW_ROUTE_ID = 'anthropic_claude_haiku_4_5_interview_primary';
36	const LIVE_PROMPT_VERSION = 'teams-live-recall-1.0.0';
37	const DEFAULT_COOLDOWN_MINUTES = 10;
38	const DEFAULT_MAX_INTERJECTIONS_PER_HOUR = 3;
39	const DEFAULT_MIN_CONFIDENCE_TO_POST = 70;
40	const RECENT_UTTERANCE_LIMIT = 18;
41	const MIN_SECONDS_BETWEEN_LIVE_QUESTIONS = 20;
42	
43	const RecallWordSchema = z.object({
44	  text: z.string(),
45	  start_timestamp: z.object({ relative: z.number().optional() }).optional(),
46	  end_timestamp: z.object({ relative: z.number().nullable().optional() }).nullable().optional(),
47	});
48	
49	const RecallTranscriptDataSchema = z.object({
50	  words: z.array(RecallWordSchema).optional(),
51	  language_code: z.string().optional(),
52	  participant: z
53	    .object({
54	      id: z.union([z.string(), z.number()]).optional(),
55	      name: z.string().nullable().optional(),
56	      email: z.string().nullable().optional(),
57	      is_host: z.boolean().optional(),
58	      platform: z.string().nullable().optional(),
59	      extra_data: z.unknown().optional(),
60	    })
61	    .optional(),
62	});
63	
64	const RecallRealtimeEventSchema = z.object({
65	  event: z.string(),
66	  data: z.object({
67	    data: RecallTranscriptDataSchema.optional(),
68	    transcript: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
69	    recording: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
70	    bot: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
71	  }),
72	});
73	
74	const PayloadSchema = z.object({
75	  receivedAt: z.string().optional(),
76	  event: RecallRealtimeEventSchema,
77	});
78	
79	const LiveQuestionDecisionSchema = z.object({
80	  shouldAsk: z.boolean(),
81	  question: z.string().optional(),
82	  reason: z.string(),
83	  confidence: z.number().int().min(0).max(100).default(0),
84	  triggerType: z.enum(['possible_contradiction', 'lull_gap', 'direct_mention', 'none']).default('none'),
85	});
86	type LiveQuestionDecision = z.infer<typeof LiveQuestionDecisionSchema>;
87	
88	const LIVE_ORACLE_SYSTEM = `You are the Oracle listening to a live Microsoft Teams meeting for POP Creations / Spruce Line.
89	
90	Your job is to decide whether to ask ONE short clarification question in the meeting chat.
91	
92	Ask only when the live discussion reveals one of these:
93	- a concrete operational rule, exception, handoff, system limitation, or workaround that is unclear;
94	- a concrete business-process question that the team is actively asking and should not lose in the spoken discussion;
95	- a possible contradiction with a recent statement in this same meeting;
96	- a question that would prevent the team from leaving an important process ambiguity unresolved.
97	
98	Do not ask because of small talk, greetings, filler, status updates, or incomplete thoughts.
99	Do not ask if the current utterance is too vague.
100	If the current utterance is already a useful business-process question, it is acceptable to restate that question concisely so it is captured in the meeting chat.
101	Do not summarize.
102	Do not answer the meeting.
103	Do not ask more than one question.
104	Keep the question under 220 characters, warm, plain text, and psychologically safe.`;
105	
106	function buildOracleClient(): OracleAIClient {
107	  return new OracleAIClient({
108	    adapters: buildStandardAdapters(),
109	    fallbackOnError: true,
110	  });
111	}
112	
113	function hashString(s: string): string {
114	  return createHash('sha256').update(s).digest('hex');
115	}
116	
117	function normalizeWords(words: z.infer<typeof RecallWordSchema>[]): string {
118	  return words
119	    .map((w) => w.text)
120	    .join(' ')
121	    .replace(/\s+([,.;:!?])/g, '$1')
122	    .replace(/\s+/g, ' ')
123	    .trim();
124	}
125	
126	function firstOffsetMs(words: z.infer<typeof RecallWordSchema>[]): number {
127	  const start = words[0]?.start_timestamp?.relative;
128	  return typeof start === 'number' ? Math.round(start * 1000) : 0;
129	}
130	
131	function clientMessageId(args: {
132	  botId: string;
133	  transcriptId: string;
134	  participantId: string;
135	  offsetMs: number;
136	  text: string;
137	}): string {
138	  const digest = createHash('sha256').update(args.text).digest('hex').slice(0, 12);
139	  return `recall-live:${args.botId}:${args.transcriptId}:${args.participantId}:${args.offsetMs}:${digest}`;
140	}
141	
142	async function resolveInterviewRoute(db: ReturnType<typeof getDirectDb>): Promise<OracleModelRoute> {
143	  const resolved = await resolveRouteFromSettings(db, 'interview');
144	  if (resolved) return resolved;
145	  const fallback = getOracleRoute(FALLBACK_INTERVIEW_ROUTE_ID);
146	  if (!fallback) throw new Error(`Fallback interview route ${FALLBACK_INTERVIEW_ROUTE_ID} missing`);
147	  return fallback;
148	}
149	
150	async function findOrCreateLiveChannel(db: ReturnType<typeof getDirectDb>, botId: string): Promise<string> {
151	  const existing = await db
152	    .select({ id: channels.id })
153	    .from(channels)
154	    .where(sql`${channels.name} = ${`Teams live meeting ${botId}`}`)
155	    .limit(1);
156	  if (existing[0]) return existing[0].id;
157	
158	  const [channel] = await db
159	    .insert(channels)
160	    .values({
161	      name: `Teams live meeting ${botId}`,
162	      isGroupChat: true,
163	      status: 'active',
164	    })
165	    .returning({ id: channels.id });
166	  if (!channel) throw new Error('failed to create live Teams channel');
167	  return channel.id;
168	}
169	
170	async function resolveEmployeeId(
171	  db: ReturnType<typeof getDirectDb>,
172	  speaker: { name: string | null; email: string | null },
173	): Promise<string | null> {
174	  if (speaker.email) {
175	    const byEmail = await db
176	      .select({ id: employees.id })
177	      .from(employees)
178	      .where(sql`lower(${employees.email}) = ${speaker.email.toLowerCase()}`)
179	      .limit(1);
180	    if (byEmail[0]) return byEmail[0].id;
181	  }
182	  if (speaker.name) {
183	    const byName = await db
184	      .select({ id: employees.id })
185	      .from(employees)
186	      .where(sql`lower(${employees.name}) = ${speaker.name.trim().toLowerCase()}`)
187	      .limit(1);
188	    if (byName[0]) return byName[0].id;
189	  }
190	  return null;
191	}
192	
193	async function loadLiveSettings(db: ReturnType<typeof getDirectDb>): Promise<{
194	  cooldownMinutes: number;
195	  maxInterjectionsPerHour: number;
196	  forceModelPass: boolean;
197	  forcePost: boolean;
198	  disablePostingLimits: boolean;
199	  minConfidenceToPost: number;
200	}> {
201	  const rows = await db
202	    .select({ key: settings.key, value: settings.value })
203	    .from(settings)
204	    .where(sql`${settings.key} in (
205	      'oracle_cooldown_minutes',
206	      'max_oracle_interjections_per_hour',
207	      'teams_live_recall_force_model_pass',
208	      'teams_live_recall_force_post',
209	      'teams_live_recall_disable_posting_limits',
210	      'teams_live_recall_min_confidence_to_post'
211	    )`);
212	  const map = new Map(rows.map((r) => [r.key, r.value]));
213	  return {
214	    cooldownMinutes:
215	      typeof map.get('oracle_cooldown_minutes') === 'number'
216	        ? (map.get('oracle_cooldown_minutes') as number)
217	        : DEFAULT_COOLDOWN_MINUTES,
218	    maxInterjectionsPerHour:
219	      typeof map.get('max_oracle_interjections_per_hour') === 'number'
220	        ? (map.get('max_oracle_interjections_per_hour') as number)
221	        : DEFAULT_MAX_INTERJECTIONS_PER_HOUR,
222	    forceModelPass: map.get('teams_live_recall_force_model_pass') === true,
223	    forcePost: map.get('teams_live_recall_force_post') === true,
224	    disablePostingLimits: map.get('teams_live_recall_disable_posting_limits') === true,
225	    minConfidenceToPost:
226	      typeof map.get('teams_live_recall_min_confidence_to_post') === 'number'
227	        ? (map.get('teams_live_recall_min_confidence_to_post') as number)
228	        : DEFAULT_MIN_CONFIDENCE_TO_POST,
229	  };
230	}
231	
232	async function channelRateState(db: ReturnType<typeof getDirectDb>, channelId: string): Promise<{
233	  minutesSinceLast: number | null;
234	  inLastHour: number;
235	}> {
236	  const last = await db
237	    .select({ createdAt: oracleInterventions.createdAt })
238	    .from(oracleInterventions)
239	    .where(eq(oracleInterventions.channelId, channelId))
240	    .orderBy(desc(oracleInterventions.createdAt))
241	    .limit(1);
242	  const minutesSinceLast = last[0]
243	    ? Math.floor((Date.now() - last[0].createdAt.getTime()) / 60_000)
244	    : null;
245	  const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
246	  const countRows = await db
247	    .select({ c: sql<number>`count(*)::int` })
248	    .from(oracleInterventions)
249	    .where(and(eq(oracleInterventions.channelId, channelId), gte(oracleInterventions.createdAt, oneHourAgo)));
250	  return { minutesSinceLast, inLastHour: countRows[0]?.c ?? 0 };
251	}
252	
253	function isWorthModelPass(text: string): boolean {
254	  if (text.length < 40) return false;
255	  return /\b(always|never|usually|not always|exception|approval|approved|send|handoff|handover|Coldlion|ERP|China|factory|routing|Burlington|TJX|Ross|Walmart|Disney|Marvel|licensor|customer|sample|production|shipping|cost|workaround|spreadsheet|process)\b/i.test(text);
256	}
257	
258	function forcedTestQuestion(text: string): string {
259	  const cleaned = stripOracleAddress(text).replace(/^test[:,]?\s*/i, '').replace(/\s+/g, ' ').trim();
260	  if (!cleaned) return 'Quick Oracle test: what should we clarify from the current discussion?';
261	  return cleaned.endsWith('?') ? cleaned : `${cleaned}?`;
262	}
263	
264	function stripOracleAddress(text: string): string {
265	  return text
266	    .replace(/^\s*(hey\s+)?oracle[:,]?\s*/i, '')
267	    .replace(/\s+/g, ' ')
268	    .trim();
269	}
270	
271	function isMetaOracleQuestion(text: string): boolean {
272	  return /\b(oracle|ai|transcription|transcript|record|recording|listen|listening|eavesdropping|bot)\b/i.test(text);
273	}
274	
275	function isDirectBusinessQuestion(text: string): boolean {
276	  const content = stripOracleAddress(text);
277	  if (!content.includes('?')) return false;
278	  if (isMetaOracleQuestion(content)) return false;
279	  return isWorthModelPass(content);
280	}
281	
282	function fallbackClarificationQuestion(text: string): string {
283	  const content = stripOracleAddress(text).replace(/\s+/g, ' ').trim();
284	  if (!content) return 'Can we clarify the business-process question that was just raised?';
285	  return `Can we clarify this process question: ${content}`;
286	}
287	
288	async function decideLiveQuestion(args: {
289	  db: ReturnType<typeof getDirectDb>;
290	  client: OracleAIClient;
291	  route: OracleModelRoute;
292	  channelId: string;
293	  currentUtterance: string;
294	  speakerName: string | null;
295	}): Promise<{ decision: LiveQuestionDecision; modelRunId: string | null }> {
296	  const recent = await args.db
297	    .select({ content: messages.content, metadataJson: messages.metadataJson, createdAt: messages.createdAt })
298	    .from(messages)
299	    .where(and(eq(messages.channelId, args.channelId), eq(messages.role, 'user'), isNull(messages.deletedAt)))
300	    .orderBy(desc(messages.createdAt))
301	    .limit(RECENT_UTTERANCE_LIMIT);
302	
303	  const recentContext = recent
304	    .slice()
305	    .reverse()
306	    .map((m, i) => {
307	      const meta = (m.metadataJson ?? {}) as { speaker?: string };
308	      return `[${i + 1}] ${meta.speaker ? `${meta.speaker}: ` : ''}${m.content}`;
309	    })
310	    .join('\n');
311	  const userContent = `Recent finalized meeting utterances (oldest first):
312	${recentContext}
313	
314	Current utterance to evaluate:
315	${args.speakerName ? `${args.speakerName}: ` : ''}${args.currentUtterance}`;
316	
317	  const blocks = [
318	    makeBlock({
319	      id: 'sys',
320	      label: 'Teams live Oracle decision system',
321	      kind: 'stable_system',
322	      content: LIVE_ORACLE_SYSTEM,
323	      cacheEligible: true,
324	      reasonIncluded: 'live Teams meeting interjection decision',
325	    }),
326	    makeBlock({
327	      id: 'utterances',
328	      label: 'Recent finalized utterances',
329	      kind: 'dynamic_input',
330	      content: userContent,
331	      cacheEligible: false,
332	      reasonIncluded: 'rolling live Teams transcript window',
333	    }),
334	  ];
335	
336	  const callStartedAt = Date.now();
337	  let modelRunId: string | null = null;
338	  try {
339	    const result = await args.client.runObject<LiveQuestionDecision>({
340	      taskType: 'interview_chat',
341	      routeId: args.route.routeId,
342	      promptVersion: LIVE_PROMPT_VERSION,
343	      blocks,
344	      schema: LiveQuestionDecisionSchema,
345	    });
346	    const latencyMs = Date.now() - callStartedAt;
347	
348	    const [contextPack] = await args.db
349	      .insert(oracleContextPacks)
350	      .values({
351	        taskType: 'interview_chat',
352	        routeId: args.route.routeId,
353	        promptVersion: LIVE_PROMPT_VERSION,
354	        stablePrefixHash: hashString(LIVE_ORACLE_SYSTEM),
355	        dynamicInputHash: hashString(userContent),
356	        blocksJson: blocks.map((b) => ({
357	          id: b.id,
358	          kind: b.kind,
359	          hash: b.hash,
360	          tokenEstimate: b.tokenEstimate,
361	        })),
362	      })
363	      .returning({ id: oracleContextPacks.id });
364	    if (!contextPack) throw new Error('failed to insert oracle_context_packs row');
365	
366	    const [modelRun] = await args.db
367	      .insert(modelRuns)
368	      .values({
369	        taskType: 'teams-live-interjection',
370	        model: args.route.modelId,
371	        provider: args.route.provider,
372	        promptVersion: LIVE_PROMPT_VERSION,
373	        inputHash: hashString(LIVE_ORACLE_SYSTEM),
374	        inputTokens: result.usage.inputTokens ?? null,
375	        outputTokens: result.usage.outputTokens ?? null,
376	        latencyMs,
377	        success: result.validation.ok,
378	        error: result.validation.ok ? null : (result.validation.error?.message ?? 'schema validation failed'),
379	      })
380	      .returning({ id: modelRuns.id });
381	    if (!modelRun) throw new Error('failed to insert model_runs row');
382	    modelRunId = modelRun.id;
383	
384	    await args.db.insert(modelRunUsageDetails).values({
385	      modelRunId: modelRun.id,
386	      contextPackId: contextPack.id,
387	      routeId: args.route.routeId,
388	      inputTokens: result.usage.inputTokens ?? null,
389	      outputTokens: result.usage.outputTokens ?? null,
390	      cachedInputTokens: result.usage.cachedInputTokens ?? null,
391	      cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
392	      reasoningTokens: result.usage.reasoningTokens ?? null,
393	      providerRequestId: result.usage.providerRequestId ?? null,
394	      rawUsageJson: (result.usage.rawUsageJson ?? null) as Record<string, unknown> | null,
395	    });
396	    await args.db.update(oracleContextPacks).set({ modelRunId: modelRun.id }).where(eq(oracleContextPacks.id, contextPack.id));
397	
398	    if (!result.validation.ok) {
399	      return {
400	        decision: { shouldAsk: false, reason: 'Decision output failed schema validation', confidence: 0, triggerType: 'none' },
401	        modelRunId,
402	      };
403	    }
404	    return { decision: result.object as LiveQuestionDecision, modelRunId };
405	  } catch (err) {
406	    const latencyMs = Date.now() - callStartedAt;
407	    const message = err instanceof Error ? err.message : String(err);
408	    try {
409	      const [modelRun] = await args.db
410	        .insert(modelRuns)
411	        .values({
412	          taskType: 'teams-live-interjection',
413	          model: args.route.modelId,
414	          provider: args.route.provider,
415	          promptVersion: LIVE_PROMPT_VERSION,
416	          latencyMs,
417	          success: false,
418	          error: message,
419	        })
420	        .returning({ id: modelRuns.id });
421	      modelRunId = modelRun?.id ?? null;
422	    } catch {
423	      /* swallow */
424	    }
425	    return {
426	      decision: { shouldAsk: false, reason: `Decision call failed: ${message}`, confidence: 0, triggerType: 'none' },
427	      modelRunId,
428	    };
429	  }
430	}
431	
432	export const teamsLiveRecallUtteranceTask = task({
433	  id: 'teams-live-recall-utterance',
434	  maxDuration: 60 * 2,
435	  run: async (rawPayload: unknown, { ctx }) => {
436	    const payload = PayloadSchema.parse(rawPayload);
437	    if (payload.event.event !== 'transcript.data') {
438	      return { ok: true, skipped: 'unsupported_event', event: payload.event.event };
439	    }
440	
441	    const data = payload.event.data.data;
442	    const words = data?.words ?? [];
443	    const text = normalizeWords(words);
444	    if (!text) return { ok: true, skipped: 'empty_utterance' };
445	
446	    const botId = payload.event.data.bot?.id ?? 'unknown-bot';
447	    const transcriptId = payload.event.data.transcript?.id ?? 'unknown-transcript';
448	    const recordingId = payload.event.data.recording?.id ?? null;
449	    const participant = data?.participant;
450	    const participantId = String(participant?.id ?? 'unknown-speaker');
451	    const speakerName = participant?.name ?? null;
452	    const speakerEmail = participant?.email ?? null;
453	    const offsetMs = firstOffsetMs(words);
454	    const clientId = clientMessageId({ botId, transcriptId, participantId, offsetMs, text });
455	
456	    const db = getDirectDb();
457	    const [jobRun] = await db
458	      .insert(jobRuns)
459	      .values({
460	        triggerRunId: ctx.run.id,
461	        jobType: 'teams-live-recall-utterance',
462	        status: 'running',
463	        startedAt: new Date(),
464	        inputJson: { botId, transcriptId, recordingId, participantId, text },
465	      })
466	      .returning({ id: jobRuns.id });
467	    if (!jobRun) throw new Error('[teams-live-recall-utterance] failed to insert job_runs row');
468	
469	    try {
470	      const channelId = await findOrCreateLiveChannel(db, botId);
471	      const existing = await db
472	        .select({ id: messages.id })
473	        .from(messages)
474	        .where(and(eq(messages.channelId, channelId), eq(messages.clientMessageId, clientId)))
475	        .limit(1);
476	      if (existing[0]) {
477	        const out = { skipped: 'duplicate', channelId, messageId: existing[0].id };
478	        await db.update(jobRuns).set({ status: 'complete', finishedAt: new Date(), outputJson: out }).where(eq(jobRuns.id, jobRun.id));
479	        return { ok: true, ...out };
480	      }
481	
482	      const employeeId = await resolveEmployeeId(db, { name: speakerName, email: speakerEmail });
483	      if (employeeId) {
484	        await db.insert(channelParticipants).values({ channelId, employeeId }).onConflictDoNothing();
485	      }
486	
487	      const [message] = await db
488	        .insert(messages)
489	        .values({
490	          channelId,
491	          employeeId,
492	          role: 'user',
493	          content: text,
494	          clientMessageId: clientId,
495	          extractionStatus: 'pending',
496	          metadataJson: {
497	            source: 'teams_live_recall',
498	            botId,
499	            transcriptId,
500	            recordingId,
501	            participantId,
502	            speaker: speakerName,
503	            speakerEmail,
504	            languageCode: data?.language_code ?? null,
505	            offsetMs,
506	            resolvedEmployeeId: employeeId,
507	          },
508	        })
509	        .returning({ id: messages.id });
510	
511	      let postedQuestion: string | null = null;
512	      let decisionReason = 'heuristic_skip';
513	      let modelRunId: string | null = null;
514	      const liveSettings = await loadLiveSettings(db);
515	      if (liveSettings.forceModelPass || isWorthModelPass(text)) {
516	        const rateState = await channelRateState(db, channelId);
517	        const cooldownSeconds =
518	          rateState.minutesSinceLast == null ? null : rateState.minutesSinceLast * 60;
519	        const cooldownClear =
520	          liveSettings.disablePostingLimits ||
521	          cooldownSeconds == null ||
522	          cooldownSeconds >= Math.max(MIN_SECONDS_BETWEEN_LIVE_QUESTIONS, liveSettings.cooldownMinutes * 60);
523	        const rateCapClear =
524	          liveSettings.disablePostingLimits || rateState.inLastHour < liveSettings.maxInterjectionsPerHour;
525	        if (cooldownClear && rateCapClear) {
526	          const client = buildOracleClient();
527	          const route = await resolveInterviewRoute(db);
528	          const decisionResult = await decideLiveQuestion({
529	            db,
530	            client,
531	            route,
532	            channelId,
533	            currentUtterance: text,
534	            speakerName,
535	          });
536	          modelRunId = decisionResult.modelRunId;
537	          decisionReason = decisionResult.decision.reason;
538	          const isForcePostTest = liveSettings.forcePost && /^oracle\s+test[:,]?/i.test(text);
539	          const shouldPost =
540	            isForcePostTest ||
541	            (decisionResult.decision.shouldAsk &&
542	              decisionResult.decision.confidence >= liveSettings.minConfidenceToPost);
543	          const questionToPost = isForcePostTest
544	            ? forcedTestQuestion(text)
545	            : decisionResult.decision.question?.trim();
546	          const fallbackQuestion =
547	            !questionToPost && isDirectBusinessQuestion(text) ? fallbackClarificationQuestion(text) : null;
548	          const questionToSend = shouldPost ? (questionToPost ?? fallbackQuestion) : fallbackQuestion;
549	          if (questionToSend) {
550	            postedQuestion = questionToSend;
551	            await sendRecallChatMessage({ botId, message: postedQuestion });
552	            const [assistantMessage] = await db
553	              .insert(messages)
554	              .values({
555	                channelId,
556	                employeeId: null,
557	                role: 'assistant',
558	                content: postedQuestion,
559	                extractionStatus: 'skipped',
560	                metadataJson: {
561	                  source: 'teams_live_recall_interjection',
562	                  botId,
563	                  triggerMessageId: message?.id ?? null,
564	                  modelRunId,
565	                  decisionReason,
566	                },
567	              })
568	              .returning({ id: messages.id });
569	            await db.insert(oracleInterventions).values({
570	              channelId,
571	              triggerType:
572	                decisionResult.decision.triggerType === 'possible_contradiction'
573	                  ? 'possible_contradiction'
574	                  : 'lull_gap',
575	              relatedMessageId: message?.id ?? null,
576	              interjectionMessageId: assistantMessage?.id ?? null,
577	              confidence: decisionResult.decision.confidence,
578	              impactScore: null,
579	              wasLiveInterjection: true,
580	              reason: fallbackQuestion
581	                ? `direct_business_question_fallback: ${decisionReason}`
582	                : isForcePostTest ? `force_post_test: ${decisionReason}` : decisionReason,
583	            });
584	          }
585	        } else {
586	          decisionReason = cooldownClear ? 'rate_cap_reached' : 'cooldown_active';
587	        }
588	      }
589	
590	      const out = {
591	        channelId,
592	        messageId: message?.id ?? null,
593	        employeeId,
594	        modelRunId,
