// Recall.ai live Teams utterance worker.
//
// This processes finalized `transcript.data` events, not partial/provisional
// STT hypotheses. Each finalized utterance is persisted as a `messages` row for
// evidence/backfill, then a tightly gated Oracle pass decides whether a useful
// one-question interjection should be posted back to the Teams meeting chat.

import { task } from '@trigger.dev/sdk/v3';
import { and, desc, eq, gte, isNull, sql } from 'drizzle-orm';
import { z } from 'zod';
import { createHash } from 'node:crypto';
import { getDirectDb } from '@oracle/db/client';
import {
  channelParticipants,
  channels,
  employees,
  jobRuns,
  messages,
  modelRuns,
  modelRunUsageDetails,
  oracleContextPacks,
  oracleInterventions,
  settings,
} from '@oracle/db/schema';
import {
  OracleAIClient,
  buildStandardAdapters,
  getOracleRoute,
  makeBlock,
  resolveRouteFromSettings,
  type OracleModelRoute,
} from '@oracle/ai';
import { sendRecallChatMessage } from '../lib/recall';

const FALLBACK_INTERVIEW_ROUTE_ID = 'anthropic_claude_haiku_4_5_interview_primary';
const LIVE_PROMPT_VERSION = 'teams-live-recall-1.0.0';
const DEFAULT_COOLDOWN_MINUTES = 10;
const DEFAULT_MAX_INTERJECTIONS_PER_HOUR = 3;
const DEFAULT_MIN_CONFIDENCE_TO_POST = 70;
const RECENT_UTTERANCE_LIMIT = 18;
const MIN_SECONDS_BETWEEN_LIVE_QUESTIONS = 20;

const RecallWordSchema = z.object({
  text: z.string(),
  start_timestamp: z.object({ relative: z.number().optional() }).optional(),
  end_timestamp: z.object({ relative: z.number().nullable().optional() }).nullable().optional(),
});

const RecallTranscriptDataSchema = z.object({
  words: z.array(RecallWordSchema).optional(),
  language_code: z.string().optional(),
  participant: z
    .object({
      id: z.union([z.string(), z.number()]).optional(),
      name: z.string().nullable().optional(),
      email: z.string().nullable().optional(),
      is_host: z.boolean().optional(),
      platform: z.string().nullable().optional(),
      extra_data: z.unknown().optional(),
    })
    .optional(),
});

const RecallRealtimeEventSchema = z.object({
  event: z.string(),
  data: z.object({
    data: RecallTranscriptDataSchema.optional(),
    transcript: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
    recording: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
    bot: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
  }),
});

const PayloadSchema = z.object({
  receivedAt: z.string().optional(),
  event: RecallRealtimeEventSchema,
});

const LiveQuestionDecisionSchema = z.object({
  shouldAsk: z.boolean(),
  question: z.string().optional(),
  reason: z.string(),
  confidence: z.number().int().min(0).max(100).default(0),
  triggerType: z.enum(['possible_contradiction', 'lull_gap', 'direct_mention', 'none']).default('none'),
});
type LiveQuestionDecision = z.infer<typeof LiveQuestionDecisionSchema>;

const LIVE_ORACLE_SYSTEM = `You are the Oracle listening to a live Microsoft Teams meeting for POP Creations / Spruce Line.

Your job is to decide whether to ask ONE short clarification question in the meeting chat.

Ask only when the live discussion reveals one of these:
- a concrete operational rule, exception, handoff, system limitation, or workaround that is unclear;
- a concrete business-process question that the team is actively asking and should not lose in the spoken discussion;
- a possible contradiction with a recent statement in this same meeting;
- a question that would prevent the team from leaving an important process ambiguity unresolved.

Do not ask because of small talk, greetings, filler, status updates, or incomplete thoughts.
Do not ask if the current utterance is too vague.
If the current utterance is already a useful business-process question, it is acceptable to restate that question concisely so it is captured in the meeting chat.
Do not summarize.
Do not answer the meeting.
Do not ask more than one question.
Keep the question under 220 characters, warm, plain text, and psychologically safe.`;

function buildOracleClient(): OracleAIClient {
  return new OracleAIClient({
    adapters: buildStandardAdapters(),
    fallbackOnError: true,
  });
}

function hashString(s: string): string {
  return createHash('sha256').update(s).digest('hex');
}

function normalizeWords(words: z.infer<typeof RecallWordSchema>[]): string {
  return words
    .map((w) => w.text)
    .join(' ')
    .replace(/\s+([,.;:!?])/g, '$1')
    .replace(/\s+/g, ' ')
    .trim();
}

function firstOffsetMs(words: z.infer<typeof RecallWordSchema>[]): number {
  const start = words[0]?.start_timestamp?.relative;
  return typeof start === 'number' ? Math.round(start * 1000) : 0;
}

function clientMessageId(args: {
  botId: string;
  transcriptId: string;
  participantId: string;
  offsetMs: number;
  text: string;
}): string {
  const digest = createHash('sha256').update(args.text).digest('hex').slice(0, 12);
  return `recall-live:${args.botId}:${args.transcriptId}:${args.participantId}:${args.offsetMs}:${digest}`;
}

async function resolveInterviewRoute(db: ReturnType<typeof getDirectDb>): Promise<OracleModelRoute> {
  const resolved = await resolveRouteFromSettings(db, 'interview');
  if (resolved) return resolved;
  const fallback = getOracleRoute(FALLBACK_INTERVIEW_ROUTE_ID);
  if (!fallback) throw new Error(`Fallback interview route ${FALLBACK_INTERVIEW_ROUTE_ID} missing`);
  return fallback;
}

async function findOrCreateLiveChannel(db: ReturnType<typeof getDirectDb>, botId: string): Promise<string> {
  const existing = await db
    .select({ id: channels.id })
    .from(channels)
    .where(sql`${channels.name} = ${`Teams live meeting ${botId}`}`)
    .limit(1);
  if (existing[0]) return existing[0].id;

  const [channel] = await db
    .insert(channels)
    .values({
      name: `Teams live meeting ${botId}`,
      isGroupChat: true,
      status: 'active',
    })
    .returning({ id: channels.id });
  if (!channel) throw new Error('failed to create live Teams channel');
  return channel.id;
}

async function resolveEmployeeId(
  db: ReturnType<typeof getDirectDb>,
  speaker: { name: string | null; email: string | null },
): Promise<string | null> {
  if (speaker.email) {
    const byEmail = await db
      .select({ id: employees.id })
      .from(employees)
      .where(sql`lower(${employees.email}) = ${speaker.email.toLowerCase()}`)
      .limit(1);
    if (byEmail[0]) return byEmail[0].id;
  }
  if (speaker.name) {
    const byName = await db
      .select({ id: employees.id })
      .from(employees)
      .where(sql`lower(${employees.name}) = ${speaker.name.trim().toLowerCase()}`)
      .limit(1);
    if (byName[0]) return byName[0].id;
  }
  return null;
}

async function loadLiveSettings(db: ReturnType<typeof getDirectDb>): Promise<{
  cooldownMinutes: number;
  maxInterjectionsPerHour: number;
  forceModelPass: boolean;
  forcePost: boolean;
  disablePostingLimits: boolean;
  minConfidenceToPost: number;
}> {
  const rows = await db
    .select({ key: settings.key, value: settings.value })
    .from(settings)
    .where(sql`${settings.key} in (
      'oracle_cooldown_minutes',
      'max_oracle_interjections_per_hour',
      'teams_live_recall_force_model_pass',
      'teams_live_recall_force_post',
      'teams_live_recall_disable_posting_limits',
      'teams_live_recall_min_confidence_to_post'
    )`);
  const map = new Map(rows.map((r) => [r.key, r.value]));
  return {
    cooldownMinutes:
      typeof map.get('oracle_cooldown_minutes') === 'number'
        ? (map.get('oracle_cooldown_minutes') as number)
        : DEFAULT_COOLDOWN_MINUTES,
    maxInterjectionsPerHour:
      typeof map.get('max_oracle_interjections_per_hour') === 'number'
        ? (map.get('max_oracle_interjections_per_hour') as number)
        : DEFAULT_MAX_INTERJECTIONS_PER_HOUR,
    forceModelPass: map.get('teams_live_recall_force_model_pass') === true,
    forcePost: map.get('teams_live_recall_force_post') === true,
    disablePostingLimits: map.get('teams_live_recall_disable_posting_limits') === true,
    minConfidenceToPost:
      typeof map.get('teams_live_recall_min_confidence_to_post') === 'number'
        ? (map.get('teams_live_recall_min_confidence_to_post') as number)
        : DEFAULT_MIN_CONFIDENCE_TO_POST,
  };
}

async function channelRateState(db: ReturnType<typeof getDirectDb>, channelId: string): Promise<{
  minutesSinceLast: number | null;
  inLastHour: number;
}> {
  const last = await db
    .select({ createdAt: oracleInterventions.createdAt })
    .from(oracleInterventions)
    .where(eq(oracleInterventions.channelId, channelId))
    .orderBy(desc(oracleInterventions.createdAt))
    .limit(1);
  const minutesSinceLast = last[0]
    ? Math.floor((Date.now() - last[0].createdAt.getTime()) / 60_000)
    : null;
  const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
  const countRows = await db
    .select({ c: sql<number>`count(*)::int` })
    .from(oracleInterventions)
    .where(and(eq(oracleInterventions.channelId, channelId), gte(oracleInterventions.createdAt, oneHourAgo)));
  return { minutesSinceLast, inLastHour: countRows[0]?.c ?? 0 };
}

function isWorthModelPass(text: string): boolean {
  if (text.length < 40) return false;
  return /\b(always|never|usually|not always|exception|approval|approved|send|handoff|handover|Coldlion|ERP|China|factory|routing|Burlington|TJX|Ross|Walmart|Disney|Marvel|licensor|customer|sample|production|shipping|cost|workaround|spreadsheet|process)\b/i.test(text);
}

function forcedTestQuestion(text: string): string {
  const cleaned = stripOracleAddress(text).replace(/^test[:,]?\s*/i, '').replace(/\s+/g, ' ').trim();
  if (!cleaned) return 'Quick Oracle test: what should we clarify from the current discussion?';
  return cleaned.endsWith('?') ? cleaned : `${cleaned}?`;
}

function stripOracleAddress(text: string): string {
  return text
    .replace(/^\s*(hey\s+)?oracle[:,]?\s*/i, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function isMetaOracleQuestion(text: string): boolean {
  return /\b(oracle|ai|transcription|transcript|record|recording|listen|listening|eavesdropping|bot)\b/i.test(text);
}

function isDirectBusinessQuestion(text: string): boolean {
  const content = stripOracleAddress(text);
  if (!content.includes('?')) return false;
  if (isMetaOracleQuestion(content)) return false;
  return isWorthModelPass(content);
}

function fallbackClarificationQuestion(text: string): string {
  const content = stripOracleAddress(text).replace(/\s+/g, ' ').trim();
  if (!content) return 'Can we clarify the business-process question that was just raised?';
  return `Can we clarify this process question: ${content}`;
}

async function decideLiveQuestion(args: {
  db: ReturnType<typeof getDirectDb>;
  client: OracleAIClient;
  route: OracleModelRoute;
  channelId: string;
  currentUtterance: string;
  speakerName: string | null;
}): Promise<{ decision: LiveQuestionDecision; modelRunId: string | null }> {
  const recent = await args.db
    .select({ content: messages.content, metadataJson: messages.metadataJson, createdAt: messages.createdAt })
    .from(messages)
    .where(and(eq(messages.channelId, args.channelId), eq(messages.role, 'user'), isNull(messages.deletedAt)))
    .orderBy(desc(messages.createdAt))
    .limit(RECENT_UTTERANCE_LIMIT);

  const recentContext = recent
    .slice()
    .reverse()
    .map((m, i) => {
      const meta = (m.metadataJson ?? {}) as { speaker?: string };
      return `[${i + 1}] ${meta.speaker ? `${meta.speaker}: ` : ''}${m.content}`;
    })
    .join('\n');
  const userContent = `Recent finalized meeting utterances (oldest first):
${recentContext}

Current utterance to evaluate:
${args.speakerName ? `${args.speakerName}: ` : ''}${args.currentUtterance}`;

  const blocks = [
    makeBlock({
      id: 'sys',
      label: 'Teams live Oracle decision system',
      kind: 'stable_system',
      content: LIVE_ORACLE_SYSTEM,
      cacheEligible: true,
      reasonIncluded: 'live Teams meeting interjection decision',
    }),
    makeBlock({
      id: 'utterances',
      label: 'Recent finalized utterances',
      kind: 'dynamic_input',
      content: userContent,
      cacheEligible: false,
      reasonIncluded: 'rolling live Teams transcript window',
    }),
  ];

  const callStartedAt = Date.now();
  let modelRunId: string | null = null;
  try {
    const result = await args.client.runObject<LiveQuestionDecision>({
      taskType: 'interview_chat',
      routeId: args.route.routeId,
      promptVersion: LIVE_PROMPT_VERSION,
      blocks,
      schema: LiveQuestionDecisionSchema,
    });
    const latencyMs = Date.now() - callStartedAt;

    const [contextPack] = await args.db
      .insert(oracleContextPacks)
      .values({
        taskType: 'interview_chat',
        routeId: args.route.routeId,
        promptVersion: LIVE_PROMPT_VERSION,
        stablePrefixHash: hashString(LIVE_ORACLE_SYSTEM),
        dynamicInputHash: hashString(userContent),
        blocksJson: blocks.map((b) => ({
          id: b.id,
          kind: b.kind,
          hash: b.hash,
          tokenEstimate: b.tokenEstimate,
        })),
      })
      .returning({ id: oracleContextPacks.id });
    if (!contextPack) throw new Error('failed to insert oracle_context_packs row');

    const [modelRun] = await args.db
      .insert(modelRuns)
      .values({
        taskType: 'teams-live-interjection',
        model: args.route.modelId,
        provider: args.route.provider,
        promptVersion: LIVE_PROMPT_VERSION,
        inputHash: hashString(LIVE_ORACLE_SYSTEM),
        inputTokens: result.usage.inputTokens ?? null,
        outputTokens: result.usage.outputTokens ?? null,
        latencyMs,
        success: result.validation.ok,
        error: result.validation.ok ? null : (result.validation.error?.message ?? 'schema validation failed'),
      })
      .returning({ id: modelRuns.id });
    if (!modelRun) throw new Error('failed to insert model_runs row');
    modelRunId = modelRun.id;

    await args.db.insert(modelRunUsageDetails).values({
      modelRunId: modelRun.id,
      contextPackId: contextPack.id,
      routeId: args.route.routeId,
      inputTokens: result.usage.inputTokens ?? null,
      outputTokens: result.usage.outputTokens ?? null,
      cachedInputTokens: result.usage.cachedInputTokens ?? null,
      cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
      reasoningTokens: result.usage.reasoningTokens ?? null,
      providerRequestId: result.usage.providerRequestId ?? null,
      rawUsageJson: (result.usage.rawUsageJson ?? null) as Record<string, unknown> | null,
    });
    await args.db.update(oracleContextPacks).set({ modelRunId: modelRun.id }).where(eq(oracleContextPacks.id, contextPack.id));

    if (!result.validation.ok) {
      return {
        decision: { shouldAsk: false, reason: 'Decision output failed schema validation', confidence: 0, triggerType: 'none' },
        modelRunId,
      };
    }
    return { decision: result.object as LiveQuestionDecision, modelRunId };
  } catch (err) {
    const latencyMs = Date.now() - callStartedAt;
    const message = err instanceof Error ? err.message : String(err);
    try {
      const [modelRun] = await args.db
        .insert(modelRuns)
        .values({
          taskType: 'teams-live-interjection',
          model: args.route.modelId,
          provider: args.route.provider,
          promptVersion: LIVE_PROMPT_VERSION,
          latencyMs,
          success: false,
          error: message,
        })
        .returning({ id: modelRuns.id });
      modelRunId = modelRun?.id ?? null;
    } catch {
      /* swallow */
    }
    return {
      decision: { shouldAsk: false, reason: `Decision call failed: ${message}`, confidence: 0, triggerType: 'none' },
      modelRunId,
    };
  }
}

export const teamsLiveRecallUtteranceTask = task({
  id: 'teams-live-recall-utterance',
  maxDuration: 60 * 2,
  run: async (rawPayload: unknown, { ctx }) => {
    const payload = PayloadSchema.parse(rawPayload);
    if (payload.event.event !== 'transcript.data') {
      return { ok: true, skipped: 'unsupported_event', event: payload.event.event };
    }

    const data = payload.event.data.data;
    const words = data?.words ?? [];
    const text = normalizeWords(words);
    if (!text) return { ok: true, skipped: 'empty_utterance' };

    const botId = payload.event.data.bot?.id ?? 'unknown-bot';
    const transcriptId = payload.event.data.transcript?.id ?? 'unknown-transcript';
    const recordingId = payload.event.data.recording?.id ?? null;
    const participant = data?.participant;
    const participantId = String(participant?.id ?? 'unknown-speaker');
    const speakerName = participant?.name ?? null;
    const speakerEmail = participant?.email ?? null;
    const offsetMs = firstOffsetMs(words);
    const clientId = clientMessageId({ botId, transcriptId, participantId, offsetMs, text });

    const db = getDirectDb();
    const [jobRun] = await db
      .insert(jobRuns)
      .values({
        triggerRunId: ctx.run.id,
        jobType: 'teams-live-recall-utterance',
        status: 'running',
        startedAt: new Date(),
        inputJson: { botId, transcriptId, recordingId, participantId, text },
      })
      .returning({ id: jobRuns.id });
    if (!jobRun) throw new Error('[teams-live-recall-utterance] failed to insert job_runs row');

    try {
      const channelId = await findOrCreateLiveChannel(db, botId);
      const existing = await db
        .select({ id: messages.id })
        .from(messages)
        .where(and(eq(messages.channelId, channelId), eq(messages.clientMessageId, clientId)))
        .limit(1);
      if (existing[0]) {
        const out = { skipped: 'duplicate', channelId, messageId: existing[0].id };
        await db.update(jobRuns).set({ status: 'complete', finishedAt: new Date(), outputJson: out }).where(eq(jobRuns.id, jobRun.id));
        return { ok: true, ...out };
      }

      const employeeId = await resolveEmployeeId(db, { name: speakerName, email: speakerEmail });
      if (employeeId) {
        await db.insert(channelParticipants).values({ channelId, employeeId }).onConflictDoNothing();
      }

      const [message] = await db
        .insert(messages)
        .values({
          channelId,
          employeeId,
          role: 'user',
          content: text,
          clientMessageId: clientId,
          extractionStatus: 'pending',
          metadataJson: {
            source: 'teams_live_recall',
            botId,
            transcriptId,
            recordingId,
            participantId,
            speaker: speakerName,
            speakerEmail,
            languageCode: data?.language_code ?? null,
            offsetMs,
            resolvedEmployeeId: employeeId,
          },
        })
        .returning({ id: messages.id });

      let postedQuestion: string | null = null;
      let decisionReason = 'heuristic_skip';
      let modelRunId: string | null = null;
      const liveSettings = await loadLiveSettings(db);
      if (liveSettings.forceModelPass || isWorthModelPass(text)) {
        const rateState = await channelRateState(db, channelId);
        const cooldownSeconds =
          rateState.minutesSinceLast == null ? null : rateState.minutesSinceLast * 60;
        const cooldownClear =
          liveSettings.disablePostingLimits ||
          cooldownSeconds == null ||
          cooldownSeconds >= Math.max(MIN_SECONDS_BETWEEN_LIVE_QUESTIONS, liveSettings.cooldownMinutes * 60);
        const rateCapClear =
          liveSettings.disablePostingLimits || rateState.inLastHour < liveSettings.maxInterjectionsPerHour;
        if (cooldownClear && rateCapClear) {
          const client = buildOracleClient();
          const route = await resolveInterviewRoute(db);
          const decisionResult = await decideLiveQuestion({
            db,
            client,
            route,
            channelId,
            currentUtterance: text,
            speakerName,
          });
          modelRunId = decisionResult.modelRunId;
          decisionReason = decisionResult.decision.reason;
          const isForcePostTest = liveSettings.forcePost && /^oracle\s+test[:,]?/i.test(text);
          const shouldPost =
            isForcePostTest ||
            (decisionResult.decision.shouldAsk &&
              decisionResult.decision.confidence >= liveSettings.minConfidenceToPost);
          const questionToPost = isForcePostTest
            ? forcedTestQuestion(text)
            : decisionResult.decision.question?.trim();
          const fallbackQuestion =
            !questionToPost && isDirectBusinessQuestion(text) ? fallbackClarificationQuestion(text) : null;
          const questionToSend = shouldPost ? (questionToPost ?? fallbackQuestion) : fallbackQuestion;
          if (questionToSend) {
            postedQuestion = questionToSend;
            await sendRecallChatMessage({ botId, message: postedQuestion });
            const [assistantMessage] = await db
              .insert(messages)
              .values({
                channelId,
                employeeId: null,
                role: 'assistant',
                content: postedQuestion,
                extractionStatus: 'skipped',
                metadataJson: {
                  source: 'teams_live_recall_interjection',
                  botId,
                  triggerMessageId: message?.id ?? null,
                  modelRunId,
                  decisionReason,
                },
              })
              .returning({ id: messages.id });
            await db.insert(oracleInterventions).values({
              channelId,
              triggerType:
                decisionResult.decision.triggerType === 'possible_contradiction'
                  ? 'possible_contradiction'
                  : 'lull_gap',
              relatedMessageId: message?.id ?? null,
              interjectionMessageId: assistantMessage?.id ?? null,
              confidence: decisionResult.decision.confidence,
              impactScore: null,
              wasLiveInterjection: true,
              reason: fallbackQuestion
                ? `direct_business_question_fallback: ${decisionReason}`
                : isForcePostTest ? `force_post_test: ${decisionReason}` : decisionReason,
            });
          }
        } else {
          decisionReason = cooldownClear ? 'rate_cap_reached' : 'cooldown_active';
        }
      }

      const out = {
        channelId,
        messageId: message?.id ?? null,
        employeeId,
        modelRunId,
        postedQuestion,
        decisionReason,
      };
      await db.update(jobRuns).set({ status: 'complete', finishedAt: new Date(), outputJson: out }).where(eq(jobRuns.id, jobRun.id));
      return { ok: true, ...out };
    } catch (err) {
      await db
        .update(jobRuns)
        .set({
          status: 'failed',
          finishedAt: new Date(),
          error: err instanceof Error ? err.message : String(err),
        })
        .where(eq(jobRuns.id, jobRun.id));
      throw err;
    }
  },
});

// Retrieval helpers for the live chat route.
//
// Spec 9.1 constraint: every chat turn fetches only
//   * recent N messages from the channel
//   * the current employee's profile
//   * top K open gaps relevant to this employee / department
//   * top K semantically relevant approved claims (hybrid pgvector + tsvector RRF)
//
// Do NOT load full brain sections — Phase 6 will pull section excerpts only when
// the search_company_knowledge tool fires.
//
// P1 #3 — Hybrid RRF retrieval:
//   searchWithRetrievalPlan() is the ONE endorsed claim-retrieval path. It runs:
//     1. Metadata pre-filter (claim_top_domains, claim_entities, claim_metadata)
//        driven by the RetrievalPlan — prevents vendor_manual from surfacing in
//        system questions, prevents vendor from polluting licensor-approval results.
//     2. Parallel pgvector cosine ranking + tsvector rank.
//     3. Reciprocal Rank Fusion (RRF, k=60) to combine both signals.
//   The fallback tsvector path (_searchFallbackTsvector) MUST stay behaviorally
//   identical for filtering — both paths build their WHERE clauses from the
//   shared buildPlanMetadataFilters() helper precisely so they cannot drift.

import { and, desc, eq, inArray, or, sql } from 'drizzle-orm';
import {
  brainSections,
  brainSectionVersions,
  channelParticipants,
  claims,
  employees,
  gaps,
  messages,
  type Employee,
  type Gap,
} from '@oracle/db/schema';
import type { OracleDb } from '@oracle/db/client';
import { EMBEDDING_DIM } from '@oracle/shared';
import { embedText } from './embeddings';
import { type RetrievalPlan } from './retrieval-plan';

// Use the full-schema-aware DB type so callers passing in the result of
// getDirectDb() / getPooledDb() type-check without casts. The retrieval helpers
// don't actually need the schema at the type level — they hand-write SQL via
// the bare drizzle-orm builders — but accepting a wider type kept the Vercel
// production build failing on a generic mismatch.
type Db = OracleDb;

export const DEFAULT_RECENT_MESSAGES = 30;
export const DEFAULT_GAPS_LIMIT = 5;

/**
 * Build the shared metadata WHERE fragments used by both the hybrid and
 * tsvector-fallback retrieval paths. Both paths use `c` as the claims alias,
 * `ctd` as the claim_top_domains join alias, and `cm` as the claim_metadata
 * join alias. Keep those alias names stable in the consuming queries.
 *
 * Important: requiredEntities matches on both (entity_type, canonical_value)
 * — matching canonical_value alone lets a name registered under a different
 * type incorrectly match.
 */
function buildPlanMetadataFilters(plan: RetrievalPlan) {
  const topDomainFilter =
    plan.topDomainHints.length > 0
      ? sql`AND ctd.top_domain_id = ANY(${plan.topDomainHints}::text[])`
      : sql``;

  // Exclude claims that carry ANY excluded top-domain. claim_top_domains is
  // multi-valued, so a direct predicate on the LEFT-JOINed ctd row would let
  // a claim survive through a different, non-excluded domain row. NOT EXISTS
  // against the full set is the only correct form. Composes with
  // topDomainFilter: a claim must (match a hint, if hints given) AND (carry no
  // excluded domain).
  const excludedTopDomainFilter =
    plan.excludedTopDomains && plan.excludedTopDomains.length > 0
      ? sql`AND NOT EXISTS (
          SELECT 1 FROM claim_top_domains _xtd
          WHERE _xtd.claim_id = c.id
            AND _xtd.top_domain_id = ANY(${plan.excludedTopDomains}::text[])
        )`
      : sql``;

  const docClassFilter =
    plan.excludedDocumentClasses && plan.excludedDocumentClasses.length > 0
      ? sql`AND (cm.document_class IS NULL OR NOT (cm.document_class = ANY(${plan.excludedDocumentClasses}::text[])))`
      : sql``;

  const timeFilter =
    plan.timeFilter === 'current'
      ? sql`AND (cm.id IS NULL OR cm.effective_until IS NULL)`
      : plan.timeFilter && plan.timeFilter.startsWith('since:')
        ? (() => {
            const since = plan.timeFilter.slice(6); // 'YYYY-MM-DD'
            return sql`AND (cm.effective_from IS NULL OR cm.effective_from >= ${since}::timestamptz)`;
          })()
        : sql``;

  // Narrowing filter (not a ranking hint): keep only claims whose
  // claim_metadata.process_stage is one of the requested stages. claim_metadata
  // is 1:1 with claims, so this predicates directly on the LEFT-JOINed cm row.
  // A claim with no metadata row (cm.process_stage IS NULL) does not satisfy a
  // specific-stage requirement and is correctly dropped — `NULL = ANY(...)`
  // evaluates to NULL, which is not TRUE.
  const processStageFilter =
    plan.processStageHints && plan.processStageHints.length > 0
      ? sql`AND cm.process_stage = ANY(${plan.processStageHints}::text[])`
      : sql``;

  const excludedEntityTypeFilter =
    plan.excludedEntityTypes && plan.excludedEntityTypes.length > 0
      ? sql`AND NOT EXISTS (
          SELECT 1 FROM claim_entities _ce
          JOIN entities _e ON _e.id = _ce.entity_id
          WHERE _ce.claim_id = c.id
            AND _e.entity_type = ANY(${plan.excludedEntityTypes}::text[])
        )`
      : sql``;

  // Tuple match on (entity_type, canonical_value) so a canonical_value
  // registered under a different entity_type cannot incidentally match.
  // unnest(arr1, arr2) zips the parallel arrays into a derived table.
  const requiredEntityFilter =
    plan.requiredEntities.length > 0
      ? sql`AND EXISTS (
          SELECT 1
          FROM claim_entities _ce2
          JOIN entities _e2 ON _e2.id = _ce2.entity_id
          JOIN unnest(
            ${plan.requiredEntities.map((e) => e.entityType)}::text[],
            ${plan.requiredEntities.map((e) => e.canonicalValue)}::text[]
          ) AS _req(t, v)
            ON _e2.entity_type = _req.t
           AND _e2.canonical_value = _req.v
          WHERE _ce2.claim_id = c.id
        )`
      : sql``;

  return {
    topDomainFilter,
    excludedTopDomainFilter,
    docClassFilter,
    timeFilter,
    processStageFilter,
    excludedEntityTypeFilter,
    requiredEntityFilter,
  };
}

export type RecentMessage = {
  id: string;
  role: 'user' | 'assistant' | 'system';
  content: string;
  createdAt: Date;
  authorName: string | null;
};

export type RelevantClaim = {
  id: string;
  summary: string;
  claimType: string;
  impactScore: number;
  confidenceScore: number;
  distance: number;
};

/** Recent messages in a channel, chronological. */
export async function getRecentMessages(
  db: Db,
  channelId: string,
  limit = DEFAULT_RECENT_MESSAGES,
): Promise<RecentMessage[]> {
  const rows = await db
    .select({
      id: messages.id,
      role: messages.role,
      content: messages.content,
      createdAt: messages.createdAt,
      authorName: employees.name,
    })
    .from(messages)
    .leftJoin(employees, eq(messages.employeeId, employees.id))
    .where(eq(messages.channelId, channelId))
    .orderBy(desc(messages.createdAt))
    .limit(limit);
  return rows.reverse();
}

/** Open gaps relevant to this employee, in priority order. */
export async function getRelevantOpenGaps(
  db: Db,
  employee: Employee,
  limit = DEFAULT_GAPS_LIMIT,
): Promise<Gap[]> {
  const depts = employee.departments.length > 0
    ? employee.departments
    : employee.department ? [employee.department] : [];

  const rows = await db
    .select()
    .from(gaps)
    .where(
      and(
        inArray(gaps.status, ['open', 'queued', 'asked']),
        or(
          eq(gaps.targetEmployeeId, employee.id),
          depts.length > 0
            ? inArray(gaps.targetDepartment, depts)
            : undefined,
        ),
      ),
    )
    .orderBy(
      sql`CASE ${gaps.priority}
            WHEN 'urgent' THEN 0
            WHEN 'high'   THEN 1
            WHEN 'medium' THEN 2
            ELSE 3 END`,
      desc(gaps.createdAt),
    )
    .limit(limit);
  return rows;
}

// ---------------------------------------------------------------------------
// Hybrid RRF retrieval — P1 #3
// ---------------------------------------------------------------------------

/**
 * Hybrid pgvector + tsvector retrieval with Reciprocal Rank Fusion (RRF).
 *
 * Implements the full RetrievalPlan spec from docs/oracle/07-knowledge-segmentation.md.
 * Filters the candidate set by top-level domain, entity type exclusions,
 * document class exclusions, and time validity BEFORE vector search.
 *
 * When no real embeddings are available (OPENAI_API_KEY not set), falls back
 * to pure tsvector ranking + metadata filter so retrieval still works in dev.
 *
 * @example
 * const plan = buildRetrievalPlanFromQuery("When does artwork go to China?");
 * const results = await searchWithRetrievalPlan(db, plan);
 */
export async function searchWithRetrievalPlan(
  db: Db,
  plan: RetrievalPlan,
): Promise<RelevantClaim[]> {
  // Enforcement: every global-fallback plan emits a structured warning so
  // operators can audit oracle_context_packs.selected_domains and improve
  // the DOMAIN_KEYWORDS heuristics in retrieval-plan.ts.
  if (plan.searchScope === 'global_fallback') {
    console.warn('[oracle:retrieval] global_fallback — searching entire claim corpus', {
      query: plan.vectorQuery.slice(0, 120),
      hint: 'Add matching keywords to DOMAIN_KEYWORDS in packages/ai/src/retrieval-plan.ts',
      impact: 'vendor_manual / licensor noise may contaminate results',
    });
  }

  const limit = plan.topK;
  const { vector, fallback } = plan.precomputedVector
    ? { vector: plan.precomputedVector, fallback: false }
    : await embedText(plan.vectorQuery);

  if (fallback) {
    return _searchFallbackTsvector(db, plan, limit);
  }

  const vec = `[${vector.join(',')}]`;
  const textQuery = plan.vectorQuery;

  const {
    topDomainFilter,
    excludedTopDomainFilter,
    docClassFilter,
    timeFilter,
    processStageFilter,
    excludedEntityTypeFilter,
    requiredEntityFilter,
  } = buildPlanMetadataFilters(plan);

  // Small department-match bonus — joins claim_metadata on department to give
  // a soft nudge to claims tagged with the requesting employee's department(s).
  // Value (0.002) is intentionally small: roughly equivalent to ~15-rank RRF
  // lift at mid-list, so it nudges without overriding semantic relevance.
  const deptHints = plan.departmentHints ?? [];
  const deptBonusCte =
    deptHints.length > 0
      ? sql`
    dept_bonus AS (
      SELECT DISTINCT cm_d.claim_id
      FROM claim_metadata cm_d
      WHERE cm_d.department = ANY(${deptHints}::text[])
    ),`
      : sql``;
  const deptBonusTerm =
    deptHints.length > 0
      ? sql`+ CASE WHEN db.claim_id IS NOT NULL THEN 0.002 ELSE 0.0 END`
      : sql``;
  const deptBonusJoin =
    deptHints.length > 0
      ? sql`LEFT JOIN dept_bonus db ON db.claim_id = vr.id`
      : sql``;

  const rows = await db.execute<{
    id: string;
    summary: string;
    claim_type: string;
    impact_score: number;
    confidence_score: number;
    distance: number;
    rrf_score: number;
  }>(sql`
    WITH
    pre_filtered AS (
      SELECT DISTINCT
        c.id, c.summary, c.claim_type, c.impact_score, c.confidence_score, c.embedding
      FROM claims c
      LEFT JOIN claim_top_domains ctd ON ctd.claim_id = c.id
      LEFT JOIN claim_metadata    cm  ON cm.claim_id  = c.id
      WHERE c.status = 'approved'
        AND c.embedding IS NOT NULL
        ${topDomainFilter}
        ${excludedTopDomainFilter}
        ${docClassFilter}
        ${timeFilter}
        ${processStageFilter}
        ${excludedEntityTypeFilter}
        ${requiredEntityFilter}
    ),
    vec_ranked AS (
      SELECT
        id, summary, claim_type, impact_score, confidence_score,
        (embedding <=> ${vec}::vector(${EMBEDDING_DIM})) AS vec_dist,
        ROW_NUMBER() OVER (
          ORDER BY embedding <=> ${vec}::vector(${EMBEDDING_DIM})
        ) AS vrank
      FROM pre_filtered
    ),
    txt_scored AS (
      SELECT
        id,
        ts_rank(
          to_tsvector('english', summary),
          plainto_tsquery('english', ${textQuery})
        ) AS ts_score
      FROM pre_filtered
      WHERE to_tsvector('english', summary) @@ plainto_tsquery('english', ${textQuery})
    ),
    txt_ranked AS (
      SELECT id, ROW_NUMBER() OVER (ORDER BY ts_score DESC) AS trank
      FROM txt_scored
    ),
    ${deptBonusCte}
    rrf AS (
      SELECT
        vr.id, vr.summary, vr.claim_type, vr.impact_score, vr.confidence_score,
        vr.vec_dist,
        1.0 / (60.0 + vr.vrank::float) +
        COALESCE(1.0 / (60.0 + tr.trank::float), 0.0)
        ${deptBonusTerm} AS rrf_score
      FROM vec_ranked vr
      LEFT JOIN txt_ranked tr ON tr.id = vr.id
      ${deptBonusJoin}
    )
    SELECT id, summary, claim_type, impact_score, confidence_score,
           vec_dist AS distance, rrf_score
    FROM rrf
    ORDER BY rrf_score DESC
    LIMIT ${limit}
  `);

  return rows.map((r) => ({
    id: r.id,
    summary: r.summary,
    claimType: r.claim_type,
    impactScore: r.impact_score,
    confidenceScore: r.confidence_score,
    distance: r.distance,
  }));
}

/**
 * Tsvector-only fallback used when OPENAI_API_KEY is absent (dev mode).
 * Applies the same metadata pre-filters from the plan.
 */
async function _searchFallbackTsvector(
  db: Db,
  plan: RetrievalPlan,
  limit: number,
): Promise<RelevantClaim[]> {
  if (plan.searchScope === 'global_fallback') {
    console.warn('[oracle:retrieval] global_fallback (tsvector path) — searching entire claim corpus', {
      query: plan.vectorQuery.slice(0, 120),
      hint: 'Add matching keywords to DOMAIN_KEYWORDS in packages/ai/src/retrieval-plan.ts',
    });
  }

  const textQuery = plan.vectorQuery;

  // Shared filter helper — keeps fallback behaviorally identical to the main
  // hybrid path for every narrowing field (top-domain hint + exclusion,
  // doc-class, time, process-stage, entity-type exclusion, required-entity),
  // so the dev fallback isn't silently weaker. Any filter added here MUST be
  // consumed in the WHERE clause below too — the parity smoke test
  // (verify:retrieval-filter-parity) fails if a key is destructured but unused.
  const {
    topDomainFilter,
    excludedTopDomainFilter,
    docClassFilter,
    timeFilter,
    processStageFilter,
    excludedEntityTypeFilter,
    requiredEntityFilter,
  } = buildPlanMetadataFilters(plan);

  const rows = await db.execute<{
    id: string;
    summary: string;
    claim_type: string;
    impact_score: number;
    confidence_score: number;
    ts_score: number;
  }>(sql`
    SELECT DISTINCT
      c.id, c.summary, c.claim_type, c.impact_score, c.confidence_score,
      ts_rank(
        to_tsvector('english', c.summary),
        plainto_tsquery('english', ${textQuery})
      ) AS ts_score
    FROM claims c
    LEFT JOIN claim_top_domains ctd ON ctd.claim_id = c.id
    LEFT JOIN claim_metadata    cm  ON cm.claim_id  = c.id
    WHERE c.status = 'approved'
      ${topDomainFilter}
      ${excludedTopDomainFilter}
      ${docClassFilter}
      ${timeFilter}
      ${processStageFilter}
      ${excludedEntityTypeFilter}
      ${requiredEntityFilter}
    ORDER BY ts_score DESC, c.impact_score DESC
    LIMIT ${limit}
  `);

  return rows.map((r) => ({
    id: r.id,
    summary: r.summary,
    claimType: r.claim_type,
    impactScore: r.impact_score,
    confidenceScore: r.confidence_score,
    distance: 1 - r.ts_score, // approximate: lower ts_score → higher distance
  }));
}

/** Fetch the current Markdown for a small set of brain sections. */
export async function getBrainSectionSnippets(
  db: Db,
  sectionIds: string[],
): Promise<Array<{ sectionId: string; title: string; markdown: string }>> {
  if (sectionIds.length === 0) return [];
  const rows = await db
    .select({
      sectionId: brainSections.id,
      title: brainSections.title,
      markdown: brainSectionVersions.markdown,
    })
    .from(brainSections)
    .leftJoin(
      brainSectionVersions,
      eq(brainSectionVersions.id, brainSections.currentVersionId),
    )
    .where(inArray(brainSections.id, sectionIds));
  return rows.map((r) => ({
    sectionId: r.sectionId,
    title: r.title,
    markdown: r.markdown ?? '',
  }));
}

/** Channel-aware gap fetch — used by the check_open_gaps tool. */
export async function getOpenGapsForChannel(
  db: Db,
  channelId: string,
  limit = DEFAULT_GAPS_LIMIT,
): Promise<Gap[]> {
  // Channel members → their departments.
  const members = await db
    .select({
      employeeId: channelParticipants.employeeId,
      department: employees.department,
      departments: employees.departments,
    })
    .from(channelParticipants)
    .innerJoin(employees, eq(employees.id, channelParticipants.employeeId))
    .where(eq(channelParticipants.channelId, channelId));

  if (members.length === 0) return [];

  const employeeIds = members.map((m) => m.employeeId);
  // Flatten all departments from all channel members (both old and new fields).
  const departments = Array.from(new Set(
    members.flatMap((m) =>
      m.departments.length > 0
        ? m.departments
        : m.department ? [m.department] : [],
    ),
  ));

  return db
    .select()
    .from(gaps)
    .where(
      and(
        inArray(gaps.status, ['open', 'queued', 'asked']),
        or(
          inArray(gaps.targetEmployeeId, employeeIds),
          departments.length > 0
            ? inArray(gaps.targetDepartment, departments)
            : undefined,
        ),
      ),
    )
    .orderBy(
      sql`CASE ${gaps.priority}
            WHEN 'urgent' THEN 0
            WHEN 'high'   THEN 1
            WHEN 'medium' THEN 2
            ELSE 3 END`,
      desc(gaps.createdAt),
    )
    .limit(limit);
}

// RetrievalPlan — spec docs/oracle/07-knowledge-segmentation.md §"What this does to retrieval code".
//
// Every query to the Oracle knowledge graph MUST go through a RetrievalPlan.
// Global vector search without metadata pre-filtering is forbidden (spec rule from
// 00-buildout-index.md "Retrieval rule" and 07-knowledge-segmentation.md).
//
// Enforcement mechanism: the `searchScope` field on every RetrievalPlan records
// HOW the scope was determined.  searchWithRetrievalPlan() emits a structured
// console.warn for every 'global_fallback' plan so operators can audit
//   SELECT ... WHERE selected_domains @> ARRAY['_global_fallback']
// in the oracle_context_packs table and improve heuristics accordingly.
//
// This module provides:
//   - RetrievalPlanSearchScope — 'domain_filtered' | 'global_fallback' | 'global_explicit'
//   - RetrievalPlan type (matches the spec shape exactly + searchScope).
//   - buildRetrievalPlanFromQuery() — lightweight synchronous heuristic builder.
//   - buildDomainScopedPlan()       — explicit domain list, no heuristic exclusions.
//   - buildGlobalRetrievalPlan()    — intentional all-corpus search.
//
// A model-backed variant (buildRetrievalPlanWithModel) can be added later when
// per-query latency budgets allow an extra cheap structured-output call.

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/**
 * How the retrieval scope was determined.
 *
 *   domain_filtered  — ≥1 domain matched from keyword heuristics or explicit
 *                      caller input. Search is scoped; vendor-manual noise is
 *                      suppressed from unrelated results.
 *   global_fallback  — 0 domains matched. Falling back to full-corpus search.
 *                      searchWithRetrievalPlan() logs a structured warning so
 *                      the gap can be closed by adding keywords to DOMAIN_KEYWORDS.
 *   global_explicit  — Caller intentionally requested all domains (e.g. the
 *                      contradiction-watcher checking a claim with no taxonomy
 *                      tags yet, or a broad synthesis sweep).
 */
export type RetrievalPlanSearchScope =
  | 'domain_filtered'
  | 'global_fallback'
  | 'global_explicit';

export type RetrievalPlan = {
  /** Up to 3 top-level domain IDs from knowledge_top_domains. Empty = search all. */
  topDomainHints: string[];
  /** Entity references the query is about; matched against canonical entity registry. */
  requiredEntities: { entityType: string; canonicalValue: string }[];
  /** Document classes to exclude from the candidate set (e.g. vendor_manual for system questions). */
  excludedDocumentClasses?: string[];
  /** Entity types whose presence in a claim should exclude it. */
  excludedEntityTypes?: string[];
  /** Top-level domain IDs to exclude from the search. */
  excludedTopDomains?: string[];
  /** Process stage hints for narrowing retrieval to a specific lifecycle stage. */
  processStageHints?: string[];
  /**
   * Time validity filter.
   *   'current' — only claims whose effective_until IS NULL (still in force).
   *   'all'     — no time filter.
   *   'since:YYYY-MM-DD' — claims effective after a given date.
   */
  timeFilter?: 'current' | 'all' | `since:${string}`;
  /** The actual semantic query string sent to the embedding + tsvector search. */
  vectorQuery: string;
  /** Maximum number of results to return. */
  topK: number;
  /**
   * How the retrieval scope was determined.
   * Used for observability — searchWithRetrievalPlan() warns on global_fallback.
   * Chat route stores this in oracle_context_packs.selected_domains as
   * '_global_fallback' so operators can query the fallback rate.
   */
  searchScope: RetrievalPlanSearchScope;
  /**
   * Optional pre-computed embedding for `vectorQuery`.
   * When present, searchWithRetrievalPlan() skips the embedText() call and uses
   * this vector directly, saving one OpenAI API round-trip.
   *
   * Must be exactly EMBEDDING_DIM (1536) floats.  The canonical use-case is
   * contradiction-watcher: it already computes/stores the claim embedding once
   * to persist it in `claims.embedding`, then threads the same vector here so
   * the subsequent ANN search doesn't embed the same summary a second time.
   */
  precomputedVector?: number[];
  /**
   * Department(s) of the employee making the request.
   * Used by searchWithRetrievalPlan() to apply a small RRF score bonus to
   * claims whose claim_metadata.department matches one of these values.
   * This is a soft signal — it nudges ranking but never filters results.
   * Sourced from employees.departments (the full array) at query time.
   */
  departmentHints?: string[];
};

export const DEFAULT_TOP_K = 8;

// ---------------------------------------------------------------------------
// Domain-hint heuristics.
// Keyword groups that map query text to top-level domain IDs.
// These domain IDs MUST match the `id` column in knowledge_top_domains
// (seeded in packages/db/migrations/sql/16_knowledge_top_domains_seed.sql).
