function buildPlanMetadataFilters(plan: RetrievalPlan) {
  // NOTE: every array below is wrapped in sql.param(...). A bare JS array in a
  // drizzle sql template is expanded into a parenthesized placeholder list
  // `($1, $2)`, which makes `ANY((...)::text[])` invalid SQL. sql.param binds
  // the whole array as ONE parameter so postgres-js serializes it as a real
  // Postgres array.
  const topDomainFilter =
    plan.topDomainHints.length > 0
      ? sql`AND ctd.top_domain_id = ANY(${sql.param(plan.topDomainHints)}::text[])`
      : sql``;

